#nullable enable // autogenerated

using MVZ2.Vanilla.Unlocks;
using MVZ2Logic;
using MVZ2Logic.Games;
using MVZ2Logic.Modding;
using MVZ2Logic.Saves;

namespace MVZ2.Vanilla
{
    public class VanillaMod : Mod
    {
        public VanillaMod() : base(spaceName)
        {
        }
        public override void Init(IGlobalGame game)
        {
            base.Init(game);
            RegisterSerializableType<SerializableLogicSaveData>();
        }

        #region 存档
        public override ModSaveData CreateSaveData()
        {
            return new LogicSaveData(spaceName);
        }
        public override ModSaveData LoadSaveData(string json)
        {
            var serializable = Deserialize<SerializableLogicSaveData>(json);
            return LogicSaveData.DeserializeFrom(serializable);
        }
        public override void PostAllSaveDataLoaded()
        {
            // 通过梦境世界第7关，并且没有通过第11关。
            var saves = Global.Saves;
            if (saves.IsUnlocked(VanillaUnlockID.dream7) && !saves.IsUnlocked(VanillaUnlockID.dream11))
            {
                saves.Unlock(VanillaUnlockID.dreamIsNightmare);
            }
        }
        #endregion

        public const float INSTA_DAMAGE_AMOUNT = 58115310;
        public const string spaceName = "mvz2";
    }
}
